const alert = $input.first().json.body || $input.first().json;

const threatScore = alert.threat_score || alert.risk_score || 0;
const severity = alert.severity || 'medium';

let blockedUntil = new Date();

if (threatScore >= 80 || severity === 'critical') {
  blockedUntil.setDate(blockedUntil.getDate() + 30);
} else if (threatScore >= 60 || severity === 'high') {
  blockedUntil.setHours(blockedUntil.getHours() + 24);
} else {
  return [{
    json: {
      ...alert,
      block_decision: 'no_block',
      reason: 'Umbral no alcanzado'
    }
  }];
}

alert.blocked_until = blockedUntil.toISOString();
alert.block_decision = 'block';
alert.block_timestamp = new Date().toISOString();

const isPrivateIP = alert.source_ip.startsWith('10.') || 
                   alert.source_ip.startsWith('192.168.') || 
                   alert.source_ip.startsWith('172.16.');

alert.is_private_ip = isPrivateIP;

alert.firewall_action = isPrivateIP ? 'log_only' : 'block';

return [{
  json: alert
}];

const item = $input.first().json;

if (item.block_decision === 'block' && !item.is_private_ip) {
  try {
    const command = `iptables -A INPUT -s ${item.source_ip} -j DROP && iptables -A OUTPUT -d ${item.source_ip} -j DROP`;

    console.log(`[SIMULADO] Ejecutar: ${command}`);

    item.firewall_command = command;
    item.firewall_executed = true;

  } catch (error) {
    item.firewall_executed = false;
    item.firewall_error = error.message;
  }
}

return [{
  json: item
}];

const result = $input.first().json;

const report = {
  timestamp: new Date().toISOString(),
  action: 'ip_blocking',
  status: result.block_decision === 'block' ? 'blocked' : 'not_blocked',
  details: {
    ip: result.source_ip,
    threat_score: result.threat_score,
    severity: result.severity,
    reason: result.reason,
    blocked_until: result.blocked_until,
    firewall_executed: result.firewall_executed || false
  },
  workflow: 'auto_blocking_v1'
};

console.log('Reporte de bloqueo:', JSON.stringify(report, null, 2));

if (result.block_decision === 'block') {
  try {
    await $http.post({
      url: 'http://logstash:8080',
      body: {
        ...report,
        type: 'ip_block_event',
        source: 'n8n_auto_block'
      },
      headers: { 'Content-Type': 'application/json' }
    });
  } catch (error) {
    console.log('Error enviando a Logstash:', error.message);
  }
}

return [{ json: report }];
